"use strict";parserFactory.register("shanghaifantasy.com",()=>new ShanghaifantasyParser);class ShanghaifantasyParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=this.buildTocUrl(e),r=(await HttpClient.fetchJson(t)).json;return this.buildChapterUrls(r)}buildTocUrl(e){let t=e.querySelector("ul#chapterList")?.getAttribute("data-cat");return`https://shanghaifantasy.com/wp-json/fiction/v1/chapters?category=${t}&order=asc&page=1&per_page=10000`}buildChapterUrls(e){return e.map(e=>({title:e.title,sourceUrl:e.permalink}))}findContent(e){let t=e.querySelector("div.contenta");return t.querySelectorAll("div, p").length<=3?e.querySelector("body > div.flex"):t}extractTitleImpl(e){return e.querySelector("title")?.textContent??null}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".patreon1, section, nav, button, template, #comments, footer, .hideme");for(let t of[...e.querySelectorAll("div")])t.removeAttribute(":style"),t.removeAttribute(":class"),t.removeAttribute("@click.outside");super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("title")?.textContent??null}findCoverImageUrl(e){return util.getFirstImgSrc(e,".flex-col")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#editdescription")]}}